const body = $input.first().json.body;
const contentType = body.contentType || 'technical-walkthrough';

const FLOWS = {
  'technical-walkthrough': `Default 5-scene flow (45-60s):
1. Hook/Problem (big-stat-reveal or kpi-dashboard) 8-12s
2. Speaker Intro (person-scorecard) 8-10s
3. How It Works (workflow-pipeline) 10-14s
4. Results/Data (data-table or kpi-dashboard) 10-14s
5. Architecture + CTA (node-graph + cta-comment) 10-14s

Transcript triggers:
- Process/workflow explanation -> workflow-pipeline
- Numbers/metrics -> kpi-dashboard or big-stat-reveal
- Before vs after -> comparison-split
- System architecture -> node-graph
- Self-introduction -> person-scorecard
- Engagement ask -> cta-comment`,

  'case-study': `Default 6-scene flow (50-70s):
1. Hook Stat (big-stat-reveal) 6-10s
2. Client Intro (person-scorecard) 8-10s
3. The Challenge (comparison-split or kpi-dashboard) 8-12s
4. The Solution (timeline-steps or workflow-pipeline) 10-14s
5. The Results (kpi-dashboard + data-table) 10-14s
6. Trust + CTA (logo-endorsement + cta-comment) 8-12s`,

  'podcast': `Flexible 4-6 scenes (40-60s):
1. Guest Intro (person-scorecard) 8-10s
2. Key Stat (big-stat-reveal) 6-8s
3-4. Topic Visualization (pick from pool) 8-12s each
5. Engagement CTA (cta-comment) 6-8s
Pool: workflow-pipeline, comparison-split, kpi-dashboard, logo-endorsement, timeline-steps, node-graph, data-table`
};

const flow = FLOWS[contentType] || FLOWS['technical-walkthrough'];

const DATA_SHAPES = `Scene data shapes:
- big-stat-reveal: { value: number, prefix?: string, suffix?: string, format?: 'abbreviated'|'percentage', color: hex, subtitle: string, comparison?: { before: {label,value}, after: {label,value} } }
- person-scorecard: { name: string, title: string, badges: [{value,label}] (2-4), bottomStrip?: string }
- kpi-dashboard: { header: string, status?: string, cards: [{label, value: number, prefix?, suffix?, color: hex}] (2-4), sparkline?: boolean }
- workflow-pipeline: { header: string, status?: string, rows: [{label, sub?, glow?: boolean, color?}][][] (1-2 rows), stats?: [{label,value}], title?: {text, accentWord?} }
- data-table: { header: string, heroStat?: {label, value: number, color, subtitle?}, table: {columns: string[], rows: [{cells: string[], color?}]} }
- node-graph: { header: string, status?: {label, color}, nodes: [{label, x: 0-100, y: 0-100, color, glow?}], edges: [{from: idx, to: idx, color?}], statusBar?: [{label,value}] }
- timeline-steps: { header: string, steps: [{label, subtitle?, status: 'complete'|'active'|'pending'}], progress?: 0-100 }
- comparison-split: { left: {header, color, icon: 'cross', items: string[]}, right: {header, color, icon: 'check', items: string[]} }
- logo-endorsement: { header: string, logos: [{name, imageUrl?}], layout?: 'grid-3x2'|'row', summaryStat?: {label,value} }
- cta-comment: { action: string, keyword: string, subtitle?: string }`;

const systemPrompt = `You are a B-roll scene generator for TrueHorizon video production. Analyze transcripts and output JSON config for animated Remotion B-roll graphics.

Content Type: ${contentType}

${flow}

${DATA_SHAPES}

Output format:
{
  "meta": { "contentType": "${contentType}", "title": "<title>", "fps": 30, "width": 1080, "height": 1920, "talkingHeadUrl": "${body.videoUrl || ''}" },
  "scenes": [{ "type": "<type>", "from": <frame>, "durationInFrames": <dur>, "data": {...} }],
  "textStrip": { "labels": [{ "from": <frame>, "label": "<text>" }] }
}

Rules:
1. Scenes sequential, no overlap. frame = seconds * 30
2. Match scenes to what speaker says at that moment
3. Colors: Teal #00D4FF, Green #00FF88, Red #FF4444, Orange #FF8C00, Purple #8B5CF6
4. Min scene: 180 frames (6s)
5. Output ONLY JSON, no markdown or explanation`;

const context = [
  body.speakerName ? `Speaker: ${body.speakerName}` : '',
  body.company ? `Company: ${body.company}` : '',
  body.metrics ? `Key metrics: ${JSON.stringify(body.metrics)}` : ''
].filter(Boolean).join('
');

const userMessage = `${context ? context + '

' : ''}Transcript:
${body.transcript}`;

return [{ json: { systemPrompt, userMessage, contentType, videoUrl: body.videoUrl || '' } }];

const response = $input.first().json;
const content = response.content?.[0]?.text || response.data?.content?.[0]?.text || '';

let config;
try {
  config = JSON.parse(content);
} catch (e) {
  const match = content.match(/```(?:json)?\n?([\s\S]*?)```/);
  if (match) {
    config = JSON.parse(match[1].trim());
  } else {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      config = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('Failed to parse scene JSON: ' + content.substring(0, 200));
    }
  }
}

const totalFrames = config.scenes.reduce(
  (max, s) => Math.max(max, s.from + s.durationInFrames), 0
);

if (!config.meta || !config.scenes || config.scenes.length === 0) {
  throw new Error('Invalid config: missing meta or scenes');
}

return [{ json: { success: true, config, totalFrames, totalSeconds: (totalFrames / 30).toFixed(1), sceneCount: config.scenes.length, sceneTypes: config.scenes.map(s => s.type) } }];
